### 6. 테스트 코드 구조

#### A. 단위 테스트 (Service)
```kotlin
// {user-module}/src/test/kotlin/.../UserServiceTest.kt
@ExtendWith(MockitoExtension::class)
class UserServiceTest {
    @Mock
    private lateinit var userRepository: UserRepository

    @InjectMocks
    private lateinit var userService: UserService

    @Test
    fun `should get user info by id`() {
        // given
        val userId = "user-123"
        val entity = UserEntity(id = userId, email = "test@example.com", ...)
        `when`(userRepository.findById(userId)).thenReturn(Optional.of(entity))

        // when
        val result = userService.getUserInfo(userId)

        // then
        assertThat(result.id).isEqualTo(userId)
        verify(userRepository).findById(userId)
    }

    @Test
    fun `should throw NotFound when user not exists`() {
        `when`(userRepository.findById("invalid")).thenReturn(Optional.empty())

        assertThrows<NotFoundException> {
            userService.getUserInfo("invalid")
        }
    }
}
```

#### B. gRPC Service 테스트
```kotlin
// UserGrpcServiceTest.kt
@ExtendWith(MockitoExtension::class)
class UserGrpcServiceTest {
    @Mock
    private lateinit var userService: UserService

    @Mock
    private lateinit var responseObserver: StreamObserver<GetUserResponse>

    @InjectMocks
    private lateinit var grpcService: UserGrpcService

    @Test
    fun `should return user via gRPC`() {
        val request = GetUserRequest.newBuilder().setUserId("user-123").build()
        val userInfo = UserInfo(id = "user-123", email = "test@example.com")

        `when`(userService.getUserInfo("user-123")).thenReturn(userInfo)

        grpcService.getUser(request, responseObserver)

        verify(responseObserver).onNext(any())
        verify(responseObserver).onCompleted()
    }
}
```

#### C. Repository 통합 테스트
```kotlin
// UserRepositoryTest.kt
@DataJpaTest
class UserRepositoryTest {
    @Autowired
    private lateinit var userRepository: UserRepository

    @Test
    fun `should find user by email`() {
        val entity = UserEntity(email = "test@example.com", ...)
        userRepository.save(entity)

        val result = userRepository.findByEmail("test@example.com")

        assertThat(result).isNotNull
        assertThat(result?.email).isEqualTo("test@example.com")
    }
}
```

